export function importSpreadsheetEntries(): number {
  const existing = loadFinancial();
  const existingIds = new Set(existing.map(e => e.id));
  const motos = loadMotos();
  const newEntries: FinancialEntry[] = [];
  for (const raw of RAW_ENTRIES) {
    if (existingIds.has(raw.id)) continue;
    const placa = (raw as any)._placa;
    let motoId = raw.motoId || null;
    if (placa && !motoId) {
      const m = motos.find(m => m.placa === placa);
      if (m) motoId = m.id;
    }
    newEntries.push({
      id: raw.id,
      tipo: raw.tipo as "receita" | "despesa",
      categoria: raw.categoria,
      subcategoria: raw.subcategoria || "",
      descricao: raw.descricao || "",
      valor: raw.valor,
      data: raw.data,
      dataPrevista: raw.dataPrevista || "",
      motoId,
      rentalId: null,
      clienteId: null,
      pago: raw.pago ?? true,
      observacao: raw.observacao || "",
      tags: raw.tags || [],
      conta: raw.conta || "",
      despesaFixa: (raw as any).despesaFixa || false,
      ignorada: (raw as any).ignorada || false,
    });
  }
  if (newEntries.length > 0) {
    saveFinancial([...existing, ...newEntries]);
  }
  return newEntries.length;
}
